export default function DesignationsSection() {
  const { data, loading, refetch } = useQuery<any>(GET_SETTINGS, {
    fetchPolicy: 'network-only'
  });
  const designations: Designation[] = data?.settings?.designations || [];
  const [upsertDesignation, { loading: addLoading }] = useMutation(UPSERT_DESIGNATION, {
    onCompleted: () => {
      refetch();
      showToast(`"${form.name}" added.`);
      setForm(EMPTY_FORM);
    },
  });
  const [deleteDesignation] = useMutation(DELETE_DESIGNATION, {
    onCompleted: () => {
      refetch();
      showToast("Designation removed.");
    },
  });

  const [form, setForm] = useState<FormState>(EMPTY_FORM);
  const [errors, setErrors] = useState<FormErrors>({});
  const [toast, setToast] = useState<string | null>(null);

  function showToast(msg: string) {
    setToast(msg);
    setTimeout(() => setToast(null), 2800);
  }

  function validate(): boolean {
    const errs: FormErrors = {};
    if (!form.name.trim()) errs.name = "Required";
    if (!form.code.trim()) errs.code = "Required";
    setErrors(errs);
    return Object.keys(errs).length === 0;
  }

  async function handleSave() {
    if (!validate()) return;
    try {
      await upsertDesignation({
        variables: { 
          input: { 
            name: form.name.trim(), 
            short_name: form.code.trim().toUpperCase()
          } 
        }
      });
    } catch (e: any) {
      showToast(e.message);
    }
  }

  async function handleDelete(id: string) {
    if (!confirm("Remove this designation?")) return;
    try {
      await deleteDesignation({ variables: { id } });
    } catch (e: any) {
      showToast(e.message);
    }
  }

  const PlusIcon = (
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2">
      <path d="M12 5v14M5 12h14"/>
    </svg>
  );
  const TrashIcon = (
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M3 6h18M8 6V4h8v2M19 6l-1 14H6L5 6"/>
    </svg>
  );
  const CheckIcon = (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#4ade80" strokeWidth="2.5">
      <path d="M20 6L9 17l-5-5"/>
    </svg>
  );
  const BadgeIcon = (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6">
      <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/>
    </svg>
  );

  return (
    <>
      <style>{CSS}</style>
      <SettingsSection
        title={`Designations (${designations.length})`}
        description="Manage job titles used in the organisation."
        icon={BadgeIcon}
      >
        <div className="ds-add-form">

          <div className="ds-field ds-field-name">
            <label className="ds-label">Designation Name</label>
            <input
              className={`ds-input${errors.name ? " error" : ""}`}
              placeholder="e.g. Professor"
              value={form.name}
              disabled={addLoading}
              onChange={(e) => { setForm(p => ({ ...p, name: e.target.value })); setErrors(p => ({ ...p, name: undefined })); }}
            />
            {errors.name && <span className="ds-error-msg">{errors.name}</span>}
          </div>

          <div className="ds-field ds-field-code">
            <label className="ds-label">Short Code</label>
            <input
              className={`ds-input${errors.code ? " error" : ""}`}
              placeholder="e.g. PROF"
              value={form.code}
              disabled={addLoading}
              onChange={(e) => { setForm(p => ({ ...p, code: e.target.value.toUpperCase() })); setErrors(p => ({ ...p, code: undefined })); }}
            />
            {errors.code && <span className="ds-error-msg">{errors.code}</span>}
          </div>

          <button className="ds-add-btn" onClick={handleSave} disabled={addLoading}>
            {PlusIcon} {addLoading ? "Adding..." : "Add Designation"}
          </button>
        </div>

        <div className="ds-divider" />

        {loading ? (
          <div className="ds-empty"><p>Loading designations...</p></div>
        ) : designations.length === 0 ? (
          <div className="ds-empty">
            <div className="ds-empty-icon">{BadgeIcon}</div>
            <p>No designations yet</p>
            <span>Add your first designation using the form above.</span>
          </div>
        ) : (
          <div className="ds-table-wrap">
            <table className="ds-table">
              <thead>
                <tr>
                  <th>Designation Name</th>
                  <th>Code</th>
                  <th>Remove</th>
                </tr>
              </thead>
              <tbody>
                {designations.map((d) => (
                  <tr key={d.id}>
                    <td><span className="dsg-name-text">{d.name}</span></td>
                    <td><span className="dsg-code-pill">{d.short_name}</span></td>
                    <td>
                      <button className="ds-del-btn" onClick={() => handleDelete(d.id)}>
                        {TrashIcon}
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </SettingsSection>

      {toast && <div className="ds-toast">{CheckIcon}{toast}</div>}
    </>
  );
}

