function formatDayShort(iso: string): string {
  if (!iso) return "";
  const days = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  return days[new Date(iso + "T00:00:00").getDay()];
}
function formatDayFull(iso: string): string {
  if (!iso) return "";
